list=['Alice', 'Bob', 'Charlie', 'Suraj','David'] # this line defines a list of names and assigns it to the variable list
name=input('enter your name: ') # this line takes input from the user and stores it in the variable name
if name == list: # this line checks if the name entered by the user is present in the list
    print('Congratulations! Your name is present in the list.') # if the condition is true, it prints a message indicating that the user's name is present in the list
else: # if the condition in the if statement is not satisfied, it means the user's name is not present in the list
    print('Sorry, your name is not present in the list.') # this line prints a message indicating that the user's name is not present in the list if the condition in the if statement is not satisfied.